sql:
SELECT COUNT(member_id) 
FROM patient_pain 
WHERE pain_level > 7;

SELECT pp.member_id, pp.pain_level
FROM patient_pain pp
WHERE pp.pain_level > (SELECT AVG(pain_level) FROM patient_pain);

external_knowledge:
- Heavy users of hospital services: Total visits > 100, Inpatient days > 50, ER visits > 0, Office visits > 0; 
- Prolonged inpatient stays: Inpatient days > 50; 
- Multiple ER visits: ER visits > 0; 
- Frequent doctor's appointments: Office visits > 0; 
- Higher-than-average pain levels: Pain level > 5, Average pain level > 3; 
- Significant amount of medications: Number of drug records > 2, Narcotics usage > 0; 
- Long intervals between prescriptions: Average gap in days between start date of drug usage and current date > 30; 
- Seeing multiple healthcare providers: Provider count > 3.

sql:
SELECT member_id, pain_level
FROM patient_pain
WHERE pain_level > 5;

SELECT member_id, AVG(claim_amount) AS avg_claim_amount
FROM medical_claims
GROUP BY member_id;

SELECT AVG(gap_duration) AS average_gap_duration 
FROM acute_drug_gap 
WHERE member_id IN (SELECT member_id FROM narcotics);

SELECT COUNT(care_id) 
FROM patient_care 
WHERE care_quality = 'excellent';
